INSERT OR IGNORE INTO compositions (title, slug, composer_id, raga_id, tala, type, language, lyrics_original, lyrics_transliterated, lyrics_translated, meaning, notation, rendition_urls, difficulty, created_at, updated_at) VALUES ('Endaro Mahanubhavulu', 'endaro-mahanubhavulu', (SELECT id FROM composers WHERE slug = 'thyagaraja' LIMIT 1), (SELECT id FROM ragas WHERE slug = 'shankarabharanam' LIMIT 1), 'Adi', 'kriti', 'telugu', 'ఎందరో మహానుభావులు', 'Pallavi:
endarO mahAnubhAvu-landariki vandanamu

Anupallavi:
canduru varNuni anda candamunu hrdayAra- vindamuna jUci brahmAnandamanu bhavincu vAr- (endarO)

caraNam 1
sAma gAna lOla manasija lAvaNya dhanya mUrdhanyul (endarO)

caraNam 2
mAnasa vana cara vara sancAramu salipi mUrti bAguga pogaDanE vAr-

caraNam 3
saraguna pAdamulaku svAntamanu sarOjamunu samarpaNamu sEyu vAr-

caraNam 4
patita pAvanuDanE parAtparuni gurinci paramArthamagu nija mArgamutOnu bADucunu sallApamutO svara layAdi rAgamula deliyu vAr-

caraNam 5
hari guNa maNimaya saramulu galamuna shObhillu bhakta kOTulilalO telivitO celimitO karuNa galgu jagamellanu sudhA drSTicE brOcu vAr-

caraNam 6
hoyalu mIra naDalu galgu sarasuni sadA kanula jucucunu pulaka sharIrula I Ananda payOdhi nimagnula I mudambunanu yashamu galavAr-

caraNam 7
parama bhAgavata mauni vara shashi vibhAkara sanaka sanandana digIsha sura kimpuruSa kanaka kashipu suta nArada tumburu pavanasUnu bAlacandra dhara shuka sarOjabhava bhUsuravarulu parama pAvanulu ghanulu shAshvatulu kamala bhava sukhamu sadAnubhavulu gAka

caraNam 8
nI mEnu nAma vaibhavambulanu nI parAkrama dhairyamula shAnta mAnasamu nIvulanu vacana satyamunu, raghuvara nIyeDa sadbhaktiyu janincakanu durmatamulanu kalla jEsinaTTi nImadi neringi santasambunanu guNa bhajanA-nanda kirtanamu jEyu vAr-

caraNam 9
bhAgavata rAmAyaNa gItAdi shruti shAstra purAnamu marmamula shivAdi sanmatamula gUDhamulan muppadi mukkOTi surAntarangamula bhAvamula nerigi bhava rAga layAdi saukhyamucE cirAyuvula galigi niravadhi sukhAtmulai tyAgarAptulaina vAr-

caraNam 10
prEma muppiri gonu vELa nAmamu dalacEvAru rAmabhaktuDaina tyAgarAjanutuni nija dAsulaina vAr-', 'Pallavi: Salutations to all those great men in this world!

Anupallavi: Those men will feel the moon-like beautiful form of God in their hearts and will be happy about it!

Charanam 1: Those who worship you who is fond of Sama gana.
Charanam 2: They control their mind and worship you who is as beautiful as Manmada.
Charanam 3: They submit their hearts at your feet.
Charanam 4: Oh the protector of people, they sing your praise with true devotion and knowledge of swara, laya & raga.
Charanam 5: They wear garlands of gems representing Hari''s qualities and with mercy see the whole world with love.
Charanam 6: They are happy to see the beautiful gait of the God every day.
Charanam 7: Surya, Chandra, Sanaka Sanandanas, Narada, Anjaneya, Siva, Brahma and other great beings enjoy the Lord''s bliss. Salutations to them.
Charanam 8: They praise your form, name, valour, peaceful heart, true words; you destroy bad thoughts; they praise your qualities.
Charanam 9: Those who know the essence of Bhagavatha, Ramayana, Gita, Sruti, Sastra, Puranas enjoy bhava, raga, tala and long life.
Charanam 10: When bhakti grows they chant your name; they are Rama bhaktas and devotees of Tyagaraja''s Lord.', 'From the Pancharatna kritis. Thyagaraja offers salutations to all great souls (mahanubhavulu). The anupallavi describes how devotees experience the moon-like beautiful form of the Lord in their hearts with bliss. The ten charanams describe various devotees: those fond of Sama gana, those who offer their hearts at the Lord''s feet, those who sing with knowledge of swara-laya-raga, and great beings like Sanaka, Sanandana, Narada, Anjaneya who enjoy eternal bliss. The final charanam says that when devotion grows, devotees chant the Lord''s name and remain true servants of Tyagaraja''s Lord (Rama).', NULL, '[{"url":"https://www.youtube.com/results?search_query=Endaro+Mahanubhavulu","label":"YouTube"}]', 'intermediate', unixepoch(), unixepoch());
INSERT OR IGNORE INTO compositions (title, slug, composer_id, raga_id, tala, type, language, lyrics_original, lyrics_transliterated, lyrics_translated, meaning, notation, rendition_urls, difficulty, created_at, updated_at) VALUES ('Brochevarevare', 'brochevarevare', (SELECT id FROM composers WHERE slug = 'thyagaraja' LIMIT 1), (SELECT id FROM ragas WHERE slug = 'shriranjani' LIMIT 1), 'Rupaka', 'kriti', 'telugu', NULL, 'Pallavi:
brOcEvaarevarE raghupate

caraNam 1
ninu vinA

caraNam 2
shrI rAmA nenaruna

caraNam 3
sakala lOka nAyaka

caraNam 4
naravara nI sari

caraNam 5
devEndrAdulu meccuTaku lanka dayatO dAna mosangi sadA

caraNam 6
vAli nokka kOla nEsi ravi bAluni rAjuga gAvinci jUci

caraNam 7
muni savanamu jUDa veNTajani khala mAricAdula hatambu cEsi

caraNam 8
bhavAbdhi taraNOp yamu nErani tyAgarAjuni karambidi', 'Pallavi: Who else (but you) will protect me, O Raghupati?

Charanams: Chief of Raghus! There is no one else to bestow affection and protect me other than you, Lord of the Universe! Who else would have donated Lanka to Vibheeshana to the delight of Indra and others? Who else would have protected Visvaamitra''s sacrifice from Maaricha? Who else could have killed Vaali with a single arrow and crowned Sugriva? And who else can lift Tyagaraja from the ocean of birth and death and lead him to salvation?', 'Thyagaraja addresses Lord Rama (Raghupati). He says there is no one but Rama to protect and love him. The charanams allude to Rama''s deeds: giving Lanka to Vibheeshana, protecting Visvaamitra''s sacrifice, slaying Vaali and crowning Sugriva, and the plea that only Rama can ferry Tyagaraja across the ocean of samsara.', NULL, NULL, 'intermediate', unixepoch(), unixepoch());
