INSERT OR IGNORE INTO compositions (title, slug, composer_id, raga_id, tala, type, language, lyrics_original, lyrics_transliterated, lyrics_translated, meaning, notation, rendition_urls, difficulty, created_at, updated_at) VALUES ('Brochevarevarura', 'brochevarevarura', (SELECT id FROM composers WHERE slug = 'thyagaraja' LIMIT 1), (SELECT id FROM ragas WHERE slug = 'shriranjani' LIMIT 1), 'Rupaka', 'kriti', 'telugu', 'బ్రోచెవరెవరురా', 'Pallavi:
brOcEvaarevarE raghupate

caraNam 1
ninu vinA

caraNam 2
shrI rAmA nenaruna

caraNam 3
sakala lOka nAyaka

caraNam 4
naravara nI sari

caraNam 5
devEndrAdulu meccuTaku lanka dayatO dAna mosangi sadA

caraNam 6
vAli nokka kOla nEsi ravi bAluni rAjuga gAvinci jUci

caraNam 7
muni savanamu jUDa veNTajani khala mAricAdula hatambu cEsi

caraNam 8
bhavAbdhi taraNOp yamu nErani tyAgarAjuni karambidi', 'Pallavi: Who else (but you) will protect me, O Raghupati?

Charanams: Chief of Raghus! There is no one else to bestow affection and protect me other than you, Lord of the Universe! Who else would have donated Lanka to Vibheeshana to the delight of Indra and others? Who else would have protected Visvaamitra''s sacrifice from Maaricha? Who else could have killed Vaali with a single arrow and crowned Sugriva? And who else can lift Tyagaraja from the ocean of birth and death and lead him to salvation?', 'Thyagaraja addresses Lord Rama (Raghupati). He says there is no one but Rama to protect and love him. The charanams allude to Rama''s deeds: giving Lanka to Vibheeshana, protecting Visvaamitra''s sacrifice, slaying Vaali and crowning Sugriva, and the plea that only Rama can ferry Tyagaraja across the ocean of samsara.', NULL, '[{"url":"https://www.youtube.com/results?search_query=Brochevarevarura+Thyagaraja","label":"YouTube"}]', 'intermediate', unixepoch(), unixepoch());
INSERT OR IGNORE INTO compositions (title, slug, composer_id, raga_id, tala, type, language, lyrics_original, lyrics_transliterated, lyrics_translated, meaning, notation, rendition_urls, difficulty, created_at, updated_at) VALUES ('Sri Nathadi Guruguho', 'sri-nathadi-guruguho', (SELECT id FROM composers WHERE slug = 'muthuswami-dikshitar' LIMIT 1), (SELECT id FROM ragas WHERE slug = 'ganamurti' LIMIT 1), 'Adi', 'kriti', 'sanskrit', 'श्री नाथादि गुरुगुहो', 'Pallavi:
Sri nathadi guruguho jayati

Anupallavi:
Sritajanapalakah saccidananda vigrahah

Charanam:
...', 'Pallavi: Victory to Guruguha, the primal Lord.

Anupallavi: Protector of devotees, embodiment of existence-consciousness-bliss.', 'Dikshitar praises Lord Subrahmanya (Guruguha) as the primordial guru and protector of devotees.', NULL, '[{"url":"https://www.youtube.com/results?search_query=Sri+Nathadi+Guruguho+Ganamurti","label":"YouTube"}]', 'intermediate', unixepoch(), unixepoch());
